export async function getBatchesByFEFO(medicineId) {
  const q = query(
    collection(db, "batches"),
    where("medicineId", "==", medicineId),
    where("quantity", ">", 0),
    orderBy("expiryDate", "asc")
  );
  const snapshot = await getDocs(q);
  return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function dispenseMedicine(medicineId, quantityNeeded, user = null) {
  const batches = await getBatchesByFEFO(medicineId);
  let remaining = quantityNeeded;

  for (const batch of batches) {
    if (remaining <= 0) break;
    const take = Math.min(batch.quantity, remaining);
    const newQty = batch.quantity - take;
    await updateDoc(doc(db, "batches", batch.id), { quantity: newQty });
    await addDoc(collection(db, "dispense_log"), {
      medicineId,
      batchId: batch.id,
      batchNo: batch.batchNo,
      quantityDispensed: take,
      dispensedAt: new Date(),
      dispensedBy: user?.name || "Unknown",
      dispensedByEmail: user?.email || "",
      dispensedByRole: user?.role || "",
    });
    remaining -= take;
  }

  if (remaining > 0) {
    alert("Not enough stock to dispense the full quantity!");
  }
}

export async function getAllMedicines() {
  const snapshot = await getDocs(collection(db, "medicines"));
  return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function getAllBatches() {
  const snapshot = await getDocs(collection(db, "batches"));
  return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function getDispenseLog() {
  const snapshot = await getDocs(collection(db, "dispense_log"));
  return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function getAlerts() {
  const alerts = [];
  const batches = await getAllBatches();
  const medicines = await getAllMedicines();
  const today = new Date();

  const THRESHOLDS = [
    { days: 7,  label: "URGENT",   severity: "urgent",   color: "danger" },
    { days: 14, label: "WARNING",  severity: "warning",  color: "warning" },
    { days: 21, label: "REMINDER", severity: "reminder", color: "info" },
  ];

  const stockMap = {};
  for (const batch of batches) {
    if (!stockMap[batch.medicineId]) stockMap[batch.medicineId] = 0;
    stockMap[batch.medicineId] += batch.quantity;

    const expiry = batch.expiryDate?.toDate ? batch.expiryDate.toDate() : new Date(batch.expiryDate);
    const daysLeft = Math.ceil((expiry - today) / (1000 * 60 * 60 * 24));

    if (batch.quantity > 0) {
      for (const threshold of THRESHOLDS) {
        if (daysLeft <= threshold.days) {
          alerts.push({
            type: "expiry",
            severity: threshold.severity,
            color: threshold.color,
            label: threshold.label,
            daysLeft,
            message: `Batch ${batch.batchNo} expires in ${daysLeft} day${daysLeft === 1 ? "" : "s"} (${expiry.toDateString()})`,
          });
          break;
        }
      }
    }
  }

  for (const med of medicines) {
    const totalQty = stockMap[med.id] || 0;

    if (totalQty === 0) {
      alerts.push({
        type: "lowstock",
        severity: "urgent",
        color: "danger",
        label: "OUT OF STOCK",
        message: `${med.name} is completely out of stock! Order immediately.`,
      });
    } else if (totalQty < med.threshold * 0.5) {
      alerts.push({
        type: "lowstock",
        severity: "urgent",
        color: "danger",
        label: "URGENT RESTOCK",
        message: `${med.name} is critically low — only ${totalQty} ${med.unit}s left (threshold: ${med.threshold}).`,
      });
    } else if (totalQty < med.threshold * 0.75) {
      alerts.push({
        type: "lowstock",
        severity: "warning",
        color: "warning",
        label: "LOW STOCK",
        message: `${med.name} is running low — ${totalQty} ${med.unit}s left (threshold: ${med.threshold}).`,
      });
    } else if (totalQty < med.threshold) {
      alerts.push({
        type: "lowstock",
        severity: "reminder",
        color: "info",
        label: "RESTOCK REMINDER",
        message: `${med.name} is approaching threshold — ${totalQty} ${med.unit}s left (threshold: ${med.threshold}).`,
      });
    }
  }

  const order = { urgent: 0, warning: 1, reminder: 2 };
  alerts.sort((a, b) => {
    const aOrder = order[a.severity] !== undefined ? order[a.severity] : 3;
    const bOrder = order[b.severity] !== undefined ? order[b.severity] : 3;
    return aOrder - bOrder;
  });

  return alerts;
}
